import { 
    Database, 
    Code, 
    ChartBar, 
    Globe,
    ArrowRight,
    FileCode,
    Table,
    FlowArrow
} from '@phosphor-icons/react';

const architectureLayers = [
    {
        id: 1,
        title: 'Data Source',
        subtitle: 'Kaggle Olist Dataset',
        icon: Database,
        color: 'bg-blue-500/10 text-blue-500',
        description: 'Brazilian e-commerce public dataset containing 100K+ orders with customer, product, and payment information.',
        details: [
            '99,441 orders from 2016-2018',
            '32,951 unique customers',
            '73,572 unique products',
            '9 interconnected CSV files'
        ]
    },
    {
        id: 2,
        title: 'Database Layer',
        subtitle: 'SQL / MongoDB',
        icon: Table,
        color: 'bg-green-500/10 text-green-500',
        description: 'Structured data storage with optimized schemas for analytical queries and fast retrieval.',
        details: [
            'Normalized relational schema',
            'Indexed for query performance',
            'Customer, Order, Product tables',
            'Payment & Review data'
        ]
    },
    {
        id: 3,
        title: 'Data Processing',
        subtitle: 'Python / Pandas',
        icon: Code,
        color: 'bg-yellow-500/10 text-yellow-500',
        description: 'ETL pipelines for data cleaning, transformation, and aggregation into analytics-ready formats.',
        details: [
            'Data cleaning & validation',
            'Feature engineering',
            'Statistical analysis',
            'Aggregation pipelines'
        ]
    },
    {
        id: 4,
        title: 'Visualization',
        subtitle: 'Recharts / Power BI',
        icon: ChartBar,
        color: 'bg-purple-500/10 text-purple-500',
        description: 'Interactive charts and dashboards for exploring KPIs, trends, and business metrics.',
        details: [
            'Revenue & order trends',
            'Customer segmentation',
            'Product performance',
            'Geographic analysis'
        ]
    },
    {
        id: 5,
        title: 'Web Application',
        subtitle: 'React + FastAPI',
        icon: Globe,
        color: 'bg-red-500/10 text-red-500',
        description: 'Modern full-stack application with responsive UI and RESTful API backend.',
        details: [
            'React 19 frontend',
            'FastAPI backend',
            'MongoDB database',
            'Tailwind CSS styling'
        ]
    }
];

const dataFlow = [
    { from: 'Raw CSV Data', to: 'Data Cleaning', description: 'Import & validation' },
    { from: 'Data Cleaning', to: 'Database', description: 'Schema mapping' },
    { from: 'Database', to: 'Analysis', description: 'Query & aggregate' },
    { from: 'Analysis', to: 'Visualization', description: 'Transform to charts' },
    { from: 'Visualization', to: 'Web App', description: 'Interactive display' }
];

export default function Architecture() {
    return (
        <div className="page-container">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                {/* Header */}
                <div className="mb-12">
                    <p className="section-label mb-2">Technical Overview</p>
                    <h1 className="text-3xl font-bold tracking-tight mb-4">System Architecture</h1>
                    <p className="text-muted-foreground max-w-2xl">
                        A comprehensive overview of the technical architecture powering this 
                        e-commerce intelligence platform, from data ingestion to visualization.
                    </p>
                </div>

                {/* Architecture Diagram */}
                <div className="border border-border rounded-md p-6 lg:p-8 bg-card mb-12" data-testid="architecture-diagram">
                    <h2 className="font-semibold mb-6 flex items-center gap-2">
                        <FlowArrow size={20} weight="duotone" className="text-primary" />
                        System Components
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-4">
                        {architectureLayers.map((layer, index) => {
                            const Icon = layer.icon;
                            return (
                                <div 
                                    key={layer.id}
                                    className={`relative animate-fade-in stagger-${index + 1}`}
                                    data-testid={`architecture-layer-${layer.id}`}
                                >
                                    <div className="border border-border rounded-md p-4 bg-background h-full">
                                        <div className={`w-10 h-10 rounded-md ${layer.color} flex items-center justify-center mb-3`}>
                                            <Icon size={20} weight="duotone" />
                                        </div>
                                        <h3 className="font-semibold text-sm mb-1">{layer.title}</h3>
                                        <p className="text-xs text-muted-foreground mb-3">{layer.subtitle}</p>
                                        <ul className="space-y-1">
                                            {layer.details.slice(0, 3).map((detail, i) => (
                                                <li key={i} className="text-xs text-muted-foreground flex items-start gap-1">
                                                    <span className="text-primary mt-1">•</span>
                                                    {detail}
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                    {index < architectureLayers.length - 1 && (
                                        <div className="hidden lg:flex absolute top-1/2 -right-2 transform -translate-y-1/2 z-10">
                                            <ArrowRight size={16} className="text-muted-foreground" />
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Data Flow */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-12">
                    <div className="border border-border rounded-md p-6 bg-card" data-testid="data-flow">
                        <h2 className="font-semibold mb-4">Data Flow Pipeline</h2>
                        <div className="space-y-3">
                            {dataFlow.map((flow, index) => (
                                <div 
                                    key={index}
                                    className="flex items-center gap-3 p-3 border border-border rounded-md bg-background"
                                >
                                    <span className="font-mono text-xs text-muted-foreground w-6">{index + 1}.</span>
                                    <span className="text-sm font-medium">{flow.from}</span>
                                    <ArrowRight size={14} className="text-primary" />
                                    <span className="text-sm font-medium">{flow.to}</span>
                                    <span className="text-xs text-muted-foreground ml-auto">{flow.description}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="border border-border rounded-md p-6 bg-card" data-testid="tech-stack">
                        <h2 className="font-semibold mb-4">Technology Stack</h2>
                        <div className="space-y-4">
                            {[
                                { category: 'Frontend', items: ['React 19', 'Tailwind CSS', 'Recharts', 'Shadcn/UI'] },
                                { category: 'Backend', items: ['FastAPI', 'Python 3.11', 'Pydantic', 'Motor (MongoDB)'] },
                                { category: 'Database', items: ['MongoDB', 'Async Operations'] },
                                { category: 'Analysis', items: ['Pandas', 'NumPy', 'SQL Queries'] }
                            ].map((stack, index) => (
                                <div key={stack.category}>
                                    <p className="text-xs font-medium uppercase tracking-wider text-muted-foreground mb-2">
                                        {stack.category}
                                    </p>
                                    <div className="flex flex-wrap gap-2">
                                        {stack.items.map((item) => (
                                            <span 
                                                key={item}
                                                className="px-2 py-1 text-xs rounded-md bg-muted font-mono"
                                            >
                                                {item}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Database Schema */}
                <div className="border border-border rounded-md p-6 bg-card" data-testid="database-schema">
                    <h2 className="font-semibold mb-4 flex items-center gap-2">
                        <FileCode size={20} weight="duotone" className="text-primary" />
                        Database Schema (Simplified)
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {[
                            {
                                table: 'orders',
                                fields: ['order_id (PK)', 'customer_id (FK)', 'order_date', 'status', 'total_amount']
                            },
                            {
                                table: 'customers',
                                fields: ['customer_id (PK)', 'name', 'email', 'country', 'segment']
                            },
                            {
                                table: 'products',
                                fields: ['product_id (PK)', 'name', 'category', 'price', 'stock_quantity']
                            }
                        ].map((schema) => (
                            <div key={schema.table} className="border border-border rounded-md overflow-hidden">
                                <div className="bg-muted px-4 py-2 border-b border-border">
                                    <p className="font-mono text-sm font-medium">{schema.table}</p>
                                </div>
                                <div className="p-4">
                                    <ul className="space-y-1">
                                        {schema.fields.map((field) => (
                                            <li key={field} className="font-mono text-xs text-muted-foreground">
                                                {field}
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
}
